   394→  def testLoggingEvents = ["passed", "skipped", "failed"]
   395→  def testShowStandardStreams = false
   396→  def testExceptionFormat = 'full'
   397→  // Gradle built-in logging only supports sending test output to stdout, which generates a lot
   398→  // of noise, especially for passing tests. We really only want output for failed tests. This
   399→  // hooks into the output and logs it (so we don't have to buffer it all in memory) and only
   400→  // saves the output for failing tests. Directory and filenames are such that you can, e.g.,
   401→  // create a Jenkins rule to collect failed test output.
   402→  def logTestStdout = {
   403→    def testId = { TestDescriptor descriptor ->
   404→      "${descriptor.className}.${descriptor.name}".toString()
   405→    }
   406→
   407→    def logFiles = new HashMap<String, File>()
   408→    def logStreams = new HashMap<String, FileOutputStream>()
   409→    beforeTest { TestDescriptor td ->
   410→      def tid = testId(td)
   411→      // truncate the file name if it's too long
   412→      def logFile = new File(
   413→              "${projectDir}/build/reports/testOutput/${tid.substring(0, Math.min(tid.size(),240))}.test.stdout"
   414→      )
   415→      logFile.parentFile.mkdirs()
   416→      logFiles.put(tid, logFile)
   417→      logStreams.put(tid, new FileOutputStream(logFile))
   418→    }
   419→    onOutput { TestDescriptor td, TestOutputEvent toe ->
   420→      def tid = testId(td)
   421→      // Some output can happen outside the context of a specific test (e.g. at the class level)
   422→      // and beforeTest/afterTest seems to not be invoked for these cases (and similarly, there's
   423→      // a TestDescriptor hierarchy that includes the thread executing the test, Gradle tasks,
   424→      // etc). We see some of these in practice and it seems like something buggy in the Gradle
   425→      // test runner since we see it *before* any tests and it is frequently not related to any
   426→      // code in the test (best guess is that it is tail output from last test). We won't have
   427→      // an output file for these, so simply ignore them. If they become critical for debugging,
   428→      // they can be seen with showStandardStreams.
   429→      if (td.name == td.className || td.className == null) {
   430→        // silently ignore output unrelated to specific test methods
   431→        return
   432→      } else if (logStreams.get(tid) == null) {
   433→        println "WARNING: unexpectedly got output for a test [${tid}]" +
   434→                " that we didn't previously see in the beforeTest hook." +
   435→                " Message for debugging: [" + toe.message + "]."
   436→        return
   437→      }
   438→      try {
   439→        logStreams.get(tid).write(toe.message.getBytes(StandardCharsets.UTF_8))
   440→      } catch (Exception e) {
   441→        println "ERROR: Failed to write output for test ${tid}"
   442→        e.printStackTrace()
   443→      }
   444→    }
   445→    afterTest { TestDescriptor td, TestResult tr ->
   446→      def tid = testId(td)
   447→      try {
   448→        logStreams.get(tid).close()
   449→        if (tr.resultType != TestResult.ResultType.FAILURE) {
   450→          logFiles.get(tid).delete()
   451→        } else {
   452→          def file = logFiles.get(tid)
   453→          println "${tid} failed, log available in ${file}"
   454→        }
   455→      } catch (Exception e) {
   456→        println "ERROR: Failed to close stdout file for ${tid}"
   457→        e.printStackTrace()
   458→      } finally {
   459→        logFiles.remove(tid)
   460→        logStreams.remove(tid)
   461→      }
   462→    }
   463→  }
